import{_ as t,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Random Image API နှင့် Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"my/Other/random-image-api-and-public-gallery.md","filePath":"my/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),i={name:"my/Other/random-image-api-and-public-gallery.md"};function o(s,e,l,c,n,p){return a(),d("div",null,[...e[0]||(e[0]=[r(`<h1 id="random-image-api-နှင့်-public-gallery" tabindex="-1">Random Image API နှင့် Public Gallery <a class="header-anchor" href="#random-image-api-နှင့်-public-gallery" aria-label="Permalink to &quot;Random Image API နှင့် Public Gallery&quot;">​</a></h1><p>ဒီ features နှစ်ခုလုံးကို ဒီနေရာမှာ configure လုပ်ပါတယ်:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API က selected directories ထဲမှ random file တစ်ခုကိုပြန်ပေးပါတယ်။ site backgrounds, avatar rotation, external pages မှ random image calls အတွက်အသုံးဝင်ပါတယ်။</p><p>enable လုပ်ပြီးနောက် ဒီလိုသုံးပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="random-image-api-settings" tabindex="-1">Random Image API Settings <a class="header-anchor" href="#random-image-api-settings" aria-label="Permalink to &quot;Random Image API Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td><code>/random</code> endpoint ကို on/off လုပ်သည်။ disabled ဖြစ်လျှင် access forbidden ဖြစ်သည်။</td></tr><tr><td>Directories</td><td>random API သုံးနိုင်တဲ့ directories ကိုကန့်သတ်သည်။ ဒီမှာမပါသော directories ကို API မသုံးနိုင်ပါ။</td></tr><tr><td>Call demo</td><td>copy လုပ်နိုင်တဲ့ random API links ဖန်တီးပေးသည်။</td></tr></tbody></table><p>directories အများကြီးရွေးနိုင်ပါတယ်။ ဥပမာ <code>/landscape/</code> နဲ့ <code>/portrait/</code> ပဲ allow လုပ်ထားလျှင် random API က အဲဒီ directories နဲ့ subdirectories ထဲမှ files တွေပဲရွေးပါမယ်။</p><h2 id="random-image-api-parameters" tabindex="-1">Random Image API Parameters <a class="header-anchor" href="#random-image-api-parameters" aria-label="Permalink to &quot;Random Image API Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Example</th><th>Purpose</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>random directory ကိုသတ်မှတ်သည်။</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>media type ကိုသတ်မှတ်သည်။ <code>image</code>, <code>video</code>, <code>audio</code> သို့မဟုတ် comma-separated combinations သုံးပါ။</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>image orientation filter လုပ်သည်။ <code>portrait</code>, <code>landscape</code>, <code>auto</code> သုံးပါ။</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>return format။ ဗလာဆို redirect, <code>url</code> ဆို plain text URL, <code>json</code> ဆို JSON။</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td><code>type=url</code> နဲ့အတူ full URL ပြန်ပေးရန်သုံးသည်။</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>age rating အလိုက် filter လုပ်သည်။</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>ဒီ tags ပါတဲ့ files တွေကိုပဲပြန်ပေးသည်။</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>ဒီ tags ပါတဲ့ files တွေကို exclude လုပ်သည်။</td></tr></tbody></table><h2 id="return-formats" tabindex="-1">Return Formats <a class="header-anchor" href="#return-formats" aria-label="Permalink to &quot;Return Formats&quot;">​</a></h2><p><code>type</code> မပါလျှင် API က random file URL ဆီတိုက်ရိုက် redirect လုပ်ပါတယ်။</p><p><code>type=url</code> ပါလျှင် text URL ပြန်ပေးပါတယ်။</p><p><code>type=json</code> ပါလျှင် file URL, file ID, file name, file type, tags, rating, related metadata ပါတဲ့ file information ပြန်ပေးပါတယ်။</p><h2 id="access-rules" tabindex="-1">Access Rules <a class="header-anchor" href="#access-rules" aria-label="Permalink to &quot;Access Rules&quot;">​</a></h2><p>Random Image API က public access rules ကိုလိုက်နာပါတယ်:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Directory restriction</td><td>allowed directories ထဲက files တွေကိုသာရွေးနိုင်သည်။</td></tr><tr><td>Blocklist</td><td>blocklisted files တွေကို random pool မှဖယ်သည်။</td></tr><tr><td>Allowlist mode</td><td>enabled ဖြစ်လျှင် public access အတွက် allowed files တွေကိုသာပြန်ပေးသည်။</td></tr><tr><td>Age rating</td><td>R12, R16, R18 နဲ့ content ဆင်တူများကို current access mode အတိုင်း filter လုပ်သည်။</td></tr></tbody></table><p>filter လုပ်ပြီး match ဖြစ်တဲ့ file မရှိလျှင် API က no matching result ပြန်ပေးပါမယ်။</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API က speed ပိုကောင်းစေရန် directory candidate pools ကို cache လုပ်ပါတယ်။</p><p>files ပြောင်းလဲပြီးနောက် ImgBed က directory cache version update လုပ်ပြီး နောက် request များမှာ candidate pool ပြန် build လုပ်ပါတယ်။ empty directories တွေကို repeated queries မဖြစ်စေရန် ခဏ cache လုပ်ပါတယ်။</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>Public gallery က visitors တွေမြင်ခွင့်ပြုထားတဲ့ directories အတွက် read-only public browsing page ပေးပါတယ်။</p><p>enable လုပ်ပြီးနောက် visitors တွေဖွင့်နိုင်ပါတယ်:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="public-gallery-settings" tabindex="-1">Public Gallery Settings <a class="header-anchor" href="#public-gallery-settings" aria-label="Permalink to &quot;Public Gallery Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>public gallery ကို on/off လုပ်သည်။ disabled ဖြစ်လျှင် visitors browse မလုပ်နိုင်ပါ။</td></tr><tr><td>Image loading mode</td><td>previews တွေက original images သုံးမလား thumbnails သုံးမလားထိန်းချုပ်သည်။</td></tr><tr><td>Open directories</td><td>visitors access လုပ်နိုင်တဲ့ directories သတ်မှတ်သည်။</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th></tr></thead><tbody><tr><td>Original</td><td>visitor page က original files ကိုတိုက်ရိုက် load လုပ်သည်။</td></tr><tr><td>Thumbnail</td><td>visitor page က faster loading အတွက် thumbnails ကိုဦးစားပေးသည်။</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories က visitors တွေဘာမြင်နိုင်မလဲဆုံးဖြတ်ပါတယ်။</p><p>ဥပမာ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Visitors တွေက ဒီလို access လုပ်နိုင်ပါမယ်:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Subdirectories တွေလည်း open လုပ်နိုင်ပါတယ်၊ ဥပမာ <code>/2026/lucky/</code>။ open မလုပ်ထားတဲ့ directories တွေကို visitors မဝင်နိုင်ပါ။</p><h2 id="public-gallery-features" tabindex="-1">Public Gallery Features <a class="header-anchor" href="#public-gallery-features" aria-label="Permalink to &quot;Public Gallery Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Browse directories</td><td>open directories ထဲက files နဲ့ subdirectories ကြည့်နိုင်သည်။</td></tr><tr><td>Search</td><td>file name, file ID, tags နဲ့ search လုပ်နိုင်သည်။</td></tr><tr><td>Type filter</td><td>images, videos, audio, other files filter လုပ်နိုင်သည်။</td></tr><tr><td>Tag filter</td><td>selected tags ကို include သို့မဟုတ် exclude လုပ်နိုင်သည်။</td></tr><tr><td>Orientation filter</td><td>landscape သို့မဟုတ် portrait images filter လုပ်နိုင်သည်။</td></tr><tr><td>Time filter</td><td>upload time range အလိုက် filter လုပ်နိုင်သည်။</td></tr><tr><td>Extension filter</td><td>file extension အလိုက် filter လုပ်နိုင်သည်။</td></tr><tr><td>Copy link</td><td>file access links copy လုပ်နိုင်သည်။</td></tr><tr><td>Media preview</td><td>visitor page မှာ images, videos, audio ကြည့်နိုင် သို့မဟုတ် play လုပ်နိုင်သည်။</td></tr></tbody></table><h2 id="public-gallery-access-rules" tabindex="-1">Public Gallery Access Rules <a class="header-anchor" href="#public-gallery-access-rules" aria-label="Permalink to &quot;Public Gallery Access Rules&quot;">​</a></h2><p>Public gallery လည်း public access rules ကိုလိုက်နာပါတယ်:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Open directories</td><td>allowed directories ကိုသာပြသည်။</td></tr><tr><td>Access mode</td><td>content ကို current age-rating access mode အလိုက် filter လုပ်သည်။</td></tr><tr><td>Allowlist mode</td><td>enabled ဖြစ်လျှင် public access အတွက် allowed files တွေကိုသာပြသည်။</td></tr><tr><td>Blocklist</td><td>blocklisted files တွေကိုဖျောက်ထားသည်။</td></tr></tbody></table>`,43)])])}const u=t(i,[["render",o]]);export{m as __pageData,u as default};
